@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">@_errorMessage</div>
}
else
{
    <!-- Summary Stats Bar -->
    <div class="stats-bar">
        <span class="stat-item">Total: @_allTasks.Count</span>
        <span class="stat-item">To Do: @GetColumnTasks("To Do").Count</span>
        <span class="stat-item">In Progress: @GetColumnTasks("In Progress").Count</span>
        <span class="stat-item">Done: @GetColumnTasks("Done").Count</span>
        <span class="stat-item stat-overdue">Overdue: @_allTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" placeholder="Search tasks by title..." @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="board-columns">
        @foreach (var status in _columns)
        {
            var tasks = GetFilteredColumnTasks(status);
            <div class="board-column">
                <div class="column-header">
                    <h3>@status (@tasks.Count)</h3>
                </div>

                <div class="column-body">
                    @foreach (var task in tasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (GetColumnIndex(status) > 0)
                                {
                                    <button class="btn-move" @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(status) - 1])">← Move Left</button>
                                }
                                @if (GetColumnIndex(status) < _columns.Length - 1)
                                {
                                    <button class="btn-move" @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(status) + 1])">Move Right →</button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (_addingToColumn == status)
                {
                    <div class="add-task-form">
                        <input type="text" placeholder="Title" @bind="_newTitle" />
                        <input type="text" placeholder="Assignee" @bind="_newAssignee" />
                        <select @bind="_newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" @bind="_newDueDate" />
                        <div class="form-actions">
                            <button class="btn-save" @onclick="SaveNewTaskAsync">Save</button>
                            <button class="btn-cancel" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn-add" @onclick="() => StartAdd(status)">+ Add Task</button>
                }
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _errorMessage;
    private string _searchText = string.Empty;

    // New task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status) =>
        _allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(_searchText) || t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private int GetColumnIndex(string status) => Array.IndexOf(_columns, status);

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = _allTasks.First(t => t.Id == taskId);
            _allTasks[_allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today;
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null)
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync returns the task; if the column isn't "To Do", move it
            if (_addingToColumn != "To Do")
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn);
                created = created with { Status = _addingToColumn };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

