                            <div class="task-actions">
                                @if (GetColumnIndex(status) > 0)
                                {
                                    <button class="btn-move" @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(status) - 1])">← Move Left</button>
                                }
                                @if (GetColumnIndex(status) < _columns.Length - 1)
                                {
                                    <button class="btn-move" @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(status) + 1])">Move Right →</button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (_addingToColumn == status)
                {
