+    padding: 0.15rem 0.5rem;
+    border-radius: 4px;
+    font-size: 0.8rem;
+    font-weight: 600;
+    color: #fff;
+    margin-bottom: 0.25rem;
+}
+
+.priority-high {
+    background-color: #e53e3e;
+}
+
+.priority-medium {
+    background-color: #d69e2e;
+}
+
+.priority-low {
+    background-color: #38a169;
+}
+
+.task-due {
+    font-size: 0.85rem;
+    color: #666;
+    margin-bottom: 0.4rem;
+}
+
+.task-actions {
+    display: flex;
+    gap: 0.4rem;
+}
+
+.btn-move {
+    font-size: 0.78rem;
+    padding: 0.2rem 0.5rem;
+    border: 1px solid #aaa;
+    border-radius: 4px;
+    background: #fff;
+    cursor: pointer;
+}
+
+.btn-move:hover {
+    background: #e8e8e8;
+}
+
+.btn-add {
+    width: 100%;
+    margin-top: 0.5rem;
+    padding: 0.4rem;
+    border: 1px dashed #aaa;
+    border-radius: 4px;
+    background: transparent;
+    cursor: pointer;
+    font-size: 0.9rem;
+    color: #555;
+}
+
+.btn-add:hover {
+    background: #e8e8e8;
+}
+
+.add-task-form {
+    display: flex;
+    flex-direction: column;
+    gap: 0.4rem;
+    margin-top: 0.5rem;
+    padding: 0.75rem;
+    background: #fff;
+    border: 1px solid #ccc;
+    border-radius: 6px;
+}
+
+.add-task-form input,
+.add-task-form select {
+    padding: 0.35rem 0.5rem;
+    border: 1px solid #ccc;
+    border-radius: 4px;
+    font-size: 0.9rem;
+}
+
+.form-actions {
+    display: flex;
+    gap: 0.4rem;
+}
+
+.btn-save {
+    padding: 0.35rem 0.75rem;
+    background: #1b6ec2;
+    color: #fff;
+    border: none;
+    border-radius: 4px;
+    cursor: pointer;
+}
+
+.btn-save:hover {
+    background: #155a9e;
+}
+
+.btn-cancel {
+    padding: 0.35rem 0.75rem;
+    background: #eee;
+    border: 1px solid #ccc;
+    border-radius: 4px;
+    cursor: pointer;
+}
+
+.btn-cancel:hover {
+    background: #ddd;
+}
+

